# Antigravity global PreToolUse — RTK rewrite for shell-like tools.
# Reads JSON from stdin; prints AGY decision JSON.

$ErrorActionPreference = 'SilentlyContinue'
$rtk = 'C:\Users\kasha\.local\bin\rtk.exe'

function Write-Allow([hashtable]$extra) {
    $o = @{ decision = 'allow' }
    if ($extra) { foreach ($k in $extra.Keys) { $o[$k] = $extra[$k] } }
    $o | ConvertTo-Json -Compress -Depth 8
}

$inputText = [Console]::In.ReadToEnd()
if ([string]::IsNullOrWhiteSpace($inputText)) {
    Write-Allow $null
    exit 0
}

try {
    $payload = $inputText | ConvertFrom-Json
} catch {
    Write-Allow $null
    exit 0
}

$toolName = $null
$cmd = $null

if ($payload.toolCall) {
    $toolName = [string]$payload.toolCall.name
    $args = $payload.toolCall.args
    if ($args) {
        if ($args.command) { $cmd = [string]$args.command }
        elseif ($args.Command) { $cmd = [string]$args.Command }
        elseif ($args.cmd) { $cmd = [string]$args.cmd }
    }
}
if (-not $toolName -and $payload.tool_name) { $toolName = [string]$payload.tool_name }
if (-not $cmd -and $payload.tool_input -and $payload.tool_input.command) {
    $cmd = [string]$payload.tool_input.command
}

$shellLike = @('Shell', 'run_command', 'run_shell_command', 'bash', 'terminal', 'execute_command', 'run_terminal_cmd')
$isShell = $false
foreach ($n in $shellLike) {
    if ($toolName -and $toolName -eq $n) { $isShell = $true; break }
    if ($toolName -and $toolName.ToLowerInvariant() -eq $n.ToLowerInvariant()) { $isShell = $true; break }
}

if (-not $isShell -or [string]::IsNullOrWhiteSpace($cmd) -or -not (Test-Path -LiteralPath $rtk)) {
    Write-Allow $null
    exit 0
}

$rewritten = & $rtk rewrite $cmd 2>$null
if ([string]::IsNullOrWhiteSpace($rewritten) -or $cmd -eq $rewritten) {
    Write-Allow $null
    exit 0
}

# AGY may ignore updated args; still allow. Prefer agent seeing message.
Write-Allow @{
    message = "RTK rewrite suggested: $($rewritten.Trim()) — prefer prefixing shell with rtk."
}
exit 0

# Antigravity global PreToolUse — block grep/file-search for source; prefer MCP.

$ErrorActionPreference = 'SilentlyContinue'

$denyMessage = @'
GREP/FILE-SEARCH blocked by global Antigravity hook.

Use codebase-memory-mcp:
  search_graph / search_code / get_code_snippet / trace_path / get_architecture
Index first if needed: index_repository(mode=full, persistence=true)

Allowed without MCP: .json .md .css .yaml .html config files when explicitly targeting those types.
'@

function Write-Json($obj) {
    $obj | ConvertTo-Json -Compress -Depth 6
}

$inputText = [Console]::In.ReadToEnd()
if ([string]::IsNullOrWhiteSpace($inputText)) {
    Write-Json @{ decision = 'allow' }
    exit 0
}

try {
    $payload = $inputText | ConvertFrom-Json
} catch {
    Write-Json @{ decision = 'allow' }
    exit 0
}

$toolName = $null
if ($payload.toolCall) { $toolName = [string]$payload.toolCall.name }
elseif ($payload.tool_name) { $toolName = [string]$payload.tool_name }

if (-not $toolName) {
    Write-Json @{ decision = 'allow' }
    exit 0
}

$blocked = @(
    'Grep', 'Glob', 'grep_search', 'file_search', 'search_file_content',
    'find_by_name', 'workspace_search', 'codebase_search', 'grep', 'glob'
)

$hit = $false
foreach ($b in $blocked) {
    if ($toolName -eq $b -or $toolName.ToLowerInvariant() -eq $b.ToLowerInvariant()) {
        $hit = $true
        break
    }
}

if (-not $hit) {
    Write-Json @{ decision = 'allow' }
    exit 0
}

# Soft+hard: deny if supported; include reason for the agent.
Write-Json @{
    decision = 'deny'
    reason   = $denyMessage
    message  = $denyMessage
}
exit 0

# Antigravity PreToolUse for Task/subagent-like tools — inject policy reminder.

$ErrorActionPreference = 'SilentlyContinue'

$policy = @'
MANDATORY: codebase-memory MCP (search_graph, search_code, get_code_snippet).
FORBIDDEN: Grep/Glob/grep_search for source code.
Shell: prefix with rtk.
'@

$inputText = [Console]::In.ReadToEnd()
