$ErrorActionPreference = 'Stop'
$settingsPath = 'C:\Users\kasha\.gemini\settings.json'
$bak = 'C:\Users\kasha\.gemini\settings.json.bak-cursor-sync'
Copy-Item -LiteralPath $settingsPath -Destination $bak -Force

$s = Get-Content -LiteralPath $settingsPath -Raw -Encoding UTF8 | ConvertFrom-Json

$mcp = New-Object psobject
$mcp | Add-Member NoteProperty 'codebase-memory-mcp' ([pscustomobject]@{
    command = 'C:/Users/kasha/AppData/Local/Programs/codebase-memory-mcp/codebase-memory-mcp.exe'
})
$mcp | Add-Member NoteProperty 'microsoft-learn' ([pscustomobject]@{
    serverUrl = 'https://learn.microsoft.com/api/mcp'
})
$mcp | Add-Member NoteProperty 'cloudflare-api' ([pscustomobject]@{
    serverUrl = 'https://mcp.cloudflare.com/mcp'
})
$mcp | Add-Member NoteProperty 'cloudflare-docs' ([pscustomobject]@{
    serverUrl = 'https://docs.mcp.cloudflare.com/mcp'
})
$s.mcpServers = $mcp

$sessionHook = [pscustomobject]@{
    matcher = 'startup'
    hooks   = @(
        [pscustomobject]@{
            type    = 'command'
            command = 'powershell -NoProfile -ExecutionPolicy Bypass -File "C:\Users\kasha\.gemini\config\hooks\session-context-agy.ps1"'
        }
    )
}
$beforeGrep = [pscustomobject]@{
    matcher = 'google_search|grep_search|file_search|Grep|Glob'
    hooks   = @(
        [pscustomobject]@{
            type    = 'command'
            command = 'powershell -NoProfile -ExecutionPolicy Bypass -File "C:\Users\kasha\.gemini\config\hooks\block-grep-agy.ps1"'
        }
    )
}
$beforeShell = [pscustomobject]@{
    matcher = 'run_shell_command|run_command|Shell|bash'
    hooks   = @(
        [pscustomobject]@{
            type    = 'command'
            command = 'powershell -NoProfile -ExecutionPolicy Bypass -File "C:\Users\kasha\.gemini\config\hooks\rtk-rewrite-agy.ps1"'
        }
    )
}

$s.hooks = [pscustomobject]@{
    SessionStart = @($sessionHook)
    BeforeTool   = @($beforeGrep, $beforeShell)
}

$json = $s | ConvertTo-Json -Depth 12
[System.IO.File]::WriteAllText($settingsPath, $json, [System.Text.UTF8Encoding]::new($false))
Write-Host 'OK: settings.json updated (backup settings.json.bak-cursor-sync)'

# Full sync: ~/.cursor global → ~/.gemini (Antigravity) global
# Run: powershell -NoProfile -ExecutionPolicy Bypass -File this.ps1

$ErrorActionPreference = 'Stop'
$cursor = Join-Path $env:USERPROFILE '.cursor'
$gemini = Join-Path $env:USERPROFILE '.gemini'
$config = Join-Path $gemini 'config'

$dirs = @(
    (Join-Path $config 'skills'),
    (Join-Path $config 'rules'),
    (Join-Path $config 'templates'),
    (Join-Path $config 'hooks'),
    (Join-Path $config 'hooks\cursor-original'),
    (Join-Path $gemini 'antigravity\skills'),
    (Join-Path $gemini 'antigravity-cli\skills'),
    (Join-Path $gemini 'antigravity-ide\skills')
)
foreach ($d in $dirs) {
    New-Item -ItemType Directory -Force -Path $d | Out-Null
}

function Invoke-Mirror($src, $dst) {
    if (-not (Test-Path -LiteralPath $src)) { Write-Host "SKIP missing $src"; return }
    & robocopy $src $dst /E /NFL /NDL /NJH /NJS /nc /ns /np | Out-Null
    Write-Host "Mirrored: $src -> $dst"
}

Invoke-Mirror (Join-Path $cursor 'skills') (Join-Path $config 'skills')
Invoke-Mirror (Join-Path $cursor 'rules') (Join-Path $config 'rules')
Invoke-Mirror (Join-Path $cursor 'templates') (Join-Path $config 'templates')
Invoke-Mirror (Join-Path $cursor 'hooks') (Join-Path $config 'hooks\cursor-original')

# Also mirror skills into product-specific global skill roots (docs diverge)
Invoke-Mirror (Join-Path $cursor 'skills') (Join-Path $gemini 'antigravity\skills')
Invoke-Mirror (Join-Path $cursor 'skills') (Join-Path $gemini 'antigravity-cli\skills')
Invoke-Mirror (Join-Path $cursor 'skills') (Join-Path $gemini 'antigravity-ide\skills')

# SETUP
$setupSrc = Join-Path $cursor 'SETUP.md'
if (Test-Path $setupSrc) {
    Copy-Item $setupSrc (Join-Path $config 'SETUP-from-cursor.md') -Force
}

# MCP — Antigravity uses serverUrl for remote
$mcp = @{
    mcpServers = @{
        'codebase-memory-mcp' = @{
            command = 'C:/Users/kasha/AppData/Local/Programs/codebase-memory-mcp/codebase-memory-mcp.exe'
        }
        'microsoft-learn' = @{
            serverUrl = 'https://learn.microsoft.com/api/mcp'
        }
        'cloudflare-api' = @{
            serverUrl = 'https://mcp.cloudflare.com/mcp'
        }
        'cloudflare-docs' = @{
            serverUrl = 'https://docs.mcp.cloudflare.com/mcp'
        }
    }
}
$mcpPath = Join-Path $config 'mcp_config.json'
($mcp | ConvertTo-Json -Depth 8) | Set-Content -LiteralPath $mcpPath -Encoding UTF8
Write-Host "Wrote $mcpPath"

# Also write CLI/IDE specific mcp if folders exist
foreach ($extra in @(
        (Join-Path $gemini 'antigravity\mcp_config.json'),
        (Join-Path $gemini 'antigravity-cli\mcp_config.json'),
        (Join-Path $gemini 'antigravity-ide\mcp_config.json')
    )) {
    $parent = Split-Path $extra -Parent
    if (-not (Test-Path $parent)) { New-Item -ItemType Directory -Force -Path $parent | Out-Null }
    Copy-Item $mcpPath $extra -Force
    Write-Host "Wrote $extra"
}

Write-Host 'Mirror step done. AGY hook scripts + settings applied by companion files.'

# Block grep/file-search for source — parity with Cursor block-grep-glob.ps1

$ErrorActionPreference = 'SilentlyContinue'

$allowedSuffixes = @(
    '.razor', '.json', '.css', '.scss', '.sass', '.less',
    '.md', '.markdown', '.mdx', '.mdc',
    '.yml', '.yaml', '.toml',
    '.txt', '.config', '.props', '.targets', '.editorconfig',
    '.http', '.xml', '.gitignore', '.dockerignore',
    '.csproj', '.sln', '.fsproj', '.vbproj',
    '.html', '.htm', '.svg', '.ico', '.env', '.env.example',
    '.lock', '.npmrc', '.nvmrc', '.prettierrc', '.py', '.toml'
)

# Note: .py listed only for explicit config-like searches; source .py still blocked via tool deny.
# Keep deny on grep tools; agent should use MCP for .py/.cs/.ts source.

$denyMessage = @'
GREP/FILE-SEARCH BLOCKED (Antigravity global = Cursor policy).

Use codebase-memory-mcp:
  1. index_status → index_repository (if needed)
  2. search_graph — symbols
  3. search_code — strings/errors
  4. get_code_snippet — body
  5. trace_path — callers

Grep allowed only for config/docs types (.json .md .css .yaml .html .csproj …) when user explicitly needs raw grep.
'@

function Write-Json($obj) { $obj | ConvertTo-Json -Compress -Depth 6 }

$inputText = [Console]::In.ReadToEnd()
if ([string]::IsNullOrWhiteSpace($inputText)) {
    Write-Json @{ decision = 'allow' }
    exit 0
}

try { $payload = $inputText | ConvertFrom-Json } catch {
    Write-Json @{ decision = 'allow' }
    exit 0
}

$toolName = $null
$argsObj = $null
if ($payload.toolCall) {
    $toolName = [string]$payload.toolCall.name
    $argsObj = $payload.toolCall.args
} elseif ($payload.tool_name) {
    $toolName = [string]$payload.tool_name
    $argsObj = $payload.tool_input
}

$blocked = @(
    'Grep', 'Glob', 'grep_search', 'file_search', 'search_file_content',
    'find_by_name', 'workspace_search', 'codebase_search', 'grep', 'glob',
    'google_search'
)

$hit = $false
if ($toolName) {
    foreach ($b in $blocked) {
        if ($toolName -eq $b -or $toolName.ToLowerInvariant() -eq $b.ToLowerInvariant()) {
            $hit = $true
            break
        }
    }
}

if (-not $hit) {
    Write-Json @{ decision = 'allow' }
    exit 0
}

# Allow if path/glob clearly targets allowed suffixes (parity with Cursor)
function Test-Allowed([string]$value) {
    if ([string]::IsNullOrWhiteSpace($value)) { return $false }
    $lower = $value.ToLowerInvariant()
    foreach ($suffix in $allowedSuffixes) {
        if ($lower.EndsWith($suffix)) { return $true }
        $bare = $suffix.TrimStart('.')
        if ($lower -like "*$bare*") { return $true }
    }
    return $false
}

$pathHint = ''
if ($argsObj) {
    if ($argsObj.path) { $pathHint = [string]$argsObj.path }
    elseif ($argsObj.Path) { $pathHint = [string]$argsObj.Path }
    elseif ($argsObj.glob) { $pathHint = [string]$argsObj.glob }
    elseif ($argsObj.glob_pattern) { $pathHint = [string]$argsObj.glob_pattern }
    elseif ($argsObj.query) { $pathHint = [string]$argsObj.query }
}

if (Test-Allowed $pathHint) {
    Write-Json @{ decision = 'allow' }
    exit 0
}

Write-Json @{
    decision = 'deny'
    reason   = $denyMessage
    message  = $denyMessage
}
exit 0

# RTK rewrite for shell tools — parity with Cursor rtk-rewrite.ps1 + rtk hook cursor

$ErrorActionPreference = 'SilentlyContinue'
