    if ($extra) { foreach ($k in $extra.Keys) { $o[$k] = $extra[$k] } }
    $o | ConvertTo-Json -Compress -Depth 10
}

$inputText = [Console]::In.ReadToEnd()
if ([string]::IsNullOrWhiteSpace($inputText)) { Write-Allow $null; exit 0 }

try { $payload = $inputText | ConvertFrom-Json } catch { Write-Allow $null; exit 0 }

$toolName = $null
$cmd = $null
if ($payload.toolCall) {
    $toolName = [string]$payload.toolCall.name
    $a = $payload.toolCall.args
    if ($a) {
        if ($a.command) { $cmd = [string]$a.command }
        elseif ($a.Command) { $cmd = [string]$a.Command }
        elseif ($a.cmd) { $cmd = [string]$a.cmd }
    }
}
if (-not $toolName -and $payload.tool_name) { $toolName = [string]$payload.tool_name }
if (-not $cmd -and $payload.tool_input -and $payload.tool_input.command) {
    $cmd = [string]$payload.tool_input.command
}

$shellLike = @('Shell', 'run_command', 'run_shell_command', 'bash', 'terminal', 'execute_command', 'run_terminal_cmd')
$isShell = $false
foreach ($n in $shellLike) {
    if ($toolName -and ($toolName -eq $n -or $toolName.ToLowerInvariant() -eq $n.ToLowerInvariant())) {
        $isShell = $true
        break
    }
}

if (-not $isShell -or [string]::IsNullOrWhiteSpace($cmd)) {
    Write-Allow $null
    exit 0
